-- Colonne de visibilité : rubriques réservées aux administratrices (idempotent)
ALTER TABLE public.admin_sections ADD COLUMN IF NOT EXISTS admin_only boolean NOT NULL DEFAULT false;

-- Renommer la rubrique existante pour distinguer les deux manuels
UPDATE public.admin_sections SET title = 'Mode d''emploi — Résidentes' WHERE title = 'Modes d''emploi';

